<template>
  <tr
    v-for="(bid, i) in getBids"
    :key ="i"
  >
    <td v-if="getCurrentCurrency === 'BTCUSDT'">{{(+bid[1]).toFixed(6)}}</td>
    <td v-else-if="getCurrentCurrency === 'BNBBTC'">{{(+bid[1]).toFixed(3)}}</td>
    <td v-else-if="getCurrentCurrency === 'ETHBTC'">{{(+bid[1]).toFixed(4)}}</td>

    <td v-if="getCurrentCurrency === 'BTCUSDT'">{{(+bid[0]).toFixed(1)}}</td>
    <td v-else-if="getCurrentCurrency === 'BNBBTC'">{{(+bid[0]).toFixed(5)}}</td>
    <td v-else-if="getCurrentCurrency === 'ETHBTC'">{{(+bid[0]).toFixed(5)}}</td>

    <td v-if="getCurrentCurrency === 'BTCUSDT'">{{(+bid[1] * +bid[0]).toFixed(3)}}</td>
    <td v-else-if="getCurrentCurrency === 'BNBBTC'">{{(+bid[1] * +bid[0]).toFixed(6)}}</td>
    <td v-else-if="getCurrentCurrency === 'ETHBTC'">{{(+bid[1] * +bid[0]).toFixed(6)}}</td>
  </tr>
</template>

<script>
import {mapGetters} from "vuex";

export default {
  name: "bid-table-item",
  computed: {
    ...mapGetters([
      "getBids",
      "getCurrentCurrency"
    ])
  }
}
</script>