<template>
  <tr
    v-for="(ask, i) in getAsks"
    :key ="i"
  >
    <td v-if="getCurrentCurrency === 'BTCUSDT'">{{(+ask[1]).toFixed(6)}}</td>
    <td v-else-if="getCurrentCurrency === 'BNBBTC'">{{(+ask[1]).toFixed(3)}}</td>
    <td v-else-if="getCurrentCurrency === 'ETHBTC'">{{(+ask[1]).toFixed(4)}}</td>

    <td v-if="getCurrentCurrency === 'BTCUSDT'">{{(+ask[0]).toFixed(1)}}</td>
    <td v-else-if="getCurrentCurrency === 'BNBBTC'">{{(+ask[0]).toFixed(5)}}</td>
    <td v-else-if="getCurrentCurrency === 'ETHBTC'">{{(+ask[0]).toFixed(5)}}</td>

    <td v-if="getCurrentCurrency === 'BTCUSDT'">{{(+ask[1] * +ask[0]).toFixed(3)}}</td>
    <td v-else-if="getCurrentCurrency === 'BNBBTC'">{{(+ask[1] * +ask[0]).toFixed(6)}}</td>
    <td v-else-if="getCurrentCurrency === 'ETHBTC'">{{(+ask[1] * +ask[0]).toFixed(6)}}</td>
  </tr>
</template>

<script>
import {mapGetters} from "vuex";

export default {
  name: "ask-table-item",
  computed: {
    ...mapGetters([
      "getAsks",
      "getCurrentCurrency"
    ])
  }
}
</script>